1	% archon:covers AlgebraicJacobian/Cohomology/MayerVietorisCore.lean AlgebraicJacobian/Cohomology/MayerVietorisCover.lean
2	\chapter{Mayer--Vietoris long exact sequence for sheaf cohomology with \(k\)-module coefficients}
3	\label{chap:Cohomology_MayerVietoris}
4	
5	This chapter constructs the Mayer--Vietoris long exact sequence for sheaf cohomology valued in \(k\)-modules, and develops the \v{C}ech-acyclicity machinery for affine basic-open covers. Together these provide the categorical engine for the Serre finiteness argument (Phase~A step~6). The carriers \(H^n(X,\mathcal F)\) and \(H^{\prime n}(U,\mathcal F)\) live in Chapter~REF and are imported here.
6	
7	The chapter introduces no protected declarations: every definition, lemma, and instance here is auxiliary, supporting the construction of \(H^1(C,\mathcal O_C)\) in Definition~REF.
8	
9	\section{Functoriality of cohomology in the open variable}
10	\label{sec:hmodule_prime_cohomologyPresheaf}
11	
12	The cohomology-of-an-open carrier \(H^{\prime n}(X,\mathcal F)\) is contravariantly functorial in the open variable \(X\). Assembling this functoriality yields a presheaf
13	\[
14	  X \longmapsto H^{\prime n}(X, \mathcal F),
15	\]
16	and, varying \(\mathcal F\) as well, a bifunctor from sheaves of \(k\)-modules to presheaves of abelian groups. The codomain is the category of abelian groups because \(\Ext\) is always valued there, regardless of the linear enrichment of the source category; the per-fiber \(k\)-module structure is inherited from the reducible wrapper on \(H^{\prime n}\).
17	
18	\begin{definition}\leanok
19	[Cohomology presheaf functor, \(H'\) flavor]
20	  \label{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
21	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheafFunctor}
22	  \uses{def:Scheme_HModule_prime}
23	
24	  Let \(k\) be a field, \(C\) a category equipped with a Grothendieck topology \(J\), and assume sheafification and \(\Ext\) exist for sheaves of \(k\)-modules on \(J\). For \(n \in \mathbb N\), define the cohomology presheaf functor
25	  \[
26	    \mathcal H^{\prime n}(k, J) \;:\; \Sheaf\,J\,(\ModuleCat\,k) \longrightarrow (C^{\op} \longrightarrow \AddCommGrpCat)
27	  \]
28	  by the standard composition of the Yoneda embedding, the free-\(k\)-module functor, sheafification, and the \(n\)-th \(\Ext\) functor.
29	\end{definition}
30	
31	\begin{proof}
32	  
33	  \leanok
34	  The body is a direct categorical composition mirroring the general sheaf-cohomology presheaf functor. Universe pinning is required because the morphism universe of the sheaf category lives one level above the object universe.
35	\end{proof}
36	
37	\begin{definition}\leanok
38	[Cohomology presheaf, \(H'\) flavor]
39	  \label{def:Scheme_HModule_prime_cohomologyPresheaf}
40	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheaf}
41	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
42	
43	  In the setting of Definition~REF, let \(\mathcal F\) be a sheaf of \(k\)-modules. For \(n \in \mathbb N\), define the cohomology presheaf
44	  \[
45	    \mathcal H^{\prime n}(\mathcal F) \;:\; C^{\op} \longrightarrow \AddCommGrpCat
46	  \]
47	  to be the evaluation of the bifunctor at \(\mathcal F\).
48	\end{definition}
49	
50	\begin{proof}
51	  
52	  \leanok
53	  Direct evaluation of the bifunctor at \(\mathcal F\).
54	\end{proof}
55	
56	\begin{remark}
57	  For every object \(X\) of \(C\), the underlying type of \(\mathcal H^{\prime n}(\mathcal F)(X)\) is definitionally equal to \(H^{\prime n}(X, \mathcal F)\). The per-fiber \(k\)-module structure is therefore inherited through the \(H'\) wrapper.
58	\end{remark}
59	
60	\begin{remark}[Lean implementation]
61	  The cohomology presheaf functor is declared as a non-computable definition and the presheaf as a non-computable abbrev, matching the reducibility conventions of the general sheaf-cohomology API. The abbrev form is load-bearing: downstream definitional unfolding needs to see through to the fiber-level \(H'\) carrier.
62	\end{remark}
63	
64	\section{Mayer--Vietoris long exact sequence}
65	\label{sec:hmodule_prime_mayer_vietoris}
66	
67	A Mayer--Vietoris square for a Grothendieck topology \(J\) on a category \(C\) is a pullback square
68	% NOTE: rendered as a 2x2 array for KaTeX (leanblueprint web); the PDF
69	% build renders the same data via tikz-cd if the package is available.
70	\[
71	  \begin{array}{ccc}
72	    X_1 & \longrightarrow & X_2 \\
73	    \downarrow & & \downarrow \\
74	    X_3 & \longrightarrow & X_4
75	  \end{array}
76	\]
77	that is a \(J\)-cover: the pair of morphisms \(X_2 \to X_4\) and \(X_3 \to X_4\) is a covering family, and \(X_1\) is the pullback. For a sheaf \(\mathcal F\), the cohomology groups of the four corners are linked by a long exact sequence whose building blocks are restriction maps, biproduct maps, and a connecting homomorphism.
78	
79	\subsection{The restriction maps}
80	
81	\begin{definition}\leanok
82	[Sum of two restriction maps]
83	  \label{def:Scheme_HModule_prime_toBiprod}
84	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
85	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf, def:Scheme_HModule_prime}
86	
87	  Let \(S\) be a Mayer--Vietoris square, \(\mathcal F\) a sheaf of \(k\)-modules, and \(n \in \mathbb N\). Define the morphism
88	  \[
89	    \toBiprod \;:\; H^{\prime n}(X_4, \mathcal F) \longrightarrow H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F)
90	  \]
91	  to be the biproduct lift of the two restriction maps induced by \(X_2 \to X_4\) and \(X_3 \to X_4\).
92	\end{definition}
93	
94	\begin{proof}
95	  
96	  \leanok
97	  The biproduct exists because the category of abelian groups has finite biproducts. The morphism is built from the contravariant functoriality of the cohomology presheaf.
98	\end{proof}
99	
100	\begin{definition}\leanok
101	[Difference of two restriction maps]
102	  \label{def:Scheme_HModule_prime_fromBiprod}
103	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod}
104	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf, def:Scheme_HModule_prime}
105	
106	  In the same setting, define the morphism
107	  \[
108	    \fromBiprod \;:\; H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F) \longrightarrow H^{\prime n}(X_1, \mathcal F)
109	  \]
110	  to be the biproduct desc of the restriction map \(X_1 \to X_2\) and the additive inverse of the restriction map \(X_1 \to X_3\).
111	\end{definition}
112	
113	\begin{proof}
114	  
115	  \leanok
116	  The negation is taken in the preadditive morphism group of the codomain category. The sign convention encodes the alternating-sum structure of the \v{C}ech complex.
117	\end{proof}
118	
119	\begin{lemma}\leanok
120	[Composition vanishes]
121	  \label{lem:Scheme_HModule_prime_toBiprod_fromBiprod}
122	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_fromBiprod}
123	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
124	
125	  In the setting above,
126	  \[
127	    \fromBiprod \circ \toBiprod \;=\; 0.
128	  \]
129	\end{lemma}
130	
131	\begin{proof}
132	  
133	  \leanok
134	  This is a formal consequence of the biproduct universal property, preadditivity, and the pullback equation \(X_1 \to X_2 \to X_4 = X_1 \to X_3 \to X_4\). Every step is independent of the value category and transfers verbatim from the abelian-group-valued setting.
135	\end{proof}
136	
137	\subsection{The short exact sequence of sheaves}
138	
139	The connecting homomorphism of the Mayer--Vietoris sequence is built from a short exact sequence of sheaves of \(k\)-modules obtained by sheafifying the Yoneda embedding composed with the free-\(k\)-module functor.
140	
141	\begin{definition}\leanok
142	[Free-\(k\)-module functor is left adjoint]
143	  \label{def:Scheme_ModuleCat_free_isLeftAdjoint}
144	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_isLeftAdjoint}
145	  Let \(k\) be a field. The free-\(k\)-module functor \(\Type \to \ModuleCat\,k\) is a left adjoint.
146	\end{definition}
147	
148	\begin{proof}
149	  \leanok
150	  The adjunction is the standard free-forgetful adjunction for \(k\)-modules. The declaration packages the existing adjunction into the typeclass-witness form.
151	\end{proof}
152	
153	\begin{lemma}\leanok
154	[Pushout of free sheaves]
155	  \label{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
156	  \lean{AlgebraicGeometry.Scheme.HModule'_isPushoutModuleCatFreeSheaf}
157	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
158	
159	  Let \(S\) be a Mayer--Vietoris square. The image of \(S\) under the composite functor
160	  \[
161	    \text{Yoneda} \;\circ\; \text{whiskering with }(\ModuleCat.\free\,k) \;\circ\; \presheafToSheaf
162	  \]
163	  is a pushout square in the category of sheaves of \(k\)-modules.
164	\end{lemma}
165	
166	\begin{proof}
167	  
168	  \leanok
169	  The original square is a pushout. Post-composition with the sheafify-compose functor preserves pushouts because the free-\(k\)-module functor is a left adjoint. A canonical isomorphism translates the resulting square into the desired shape.
170	\end{proof}
171	
172	\begin{definition}\leanok
173	[Short complex of free sheaves]
174	  \label{def:Scheme_HModule_prime_shortComplex}
175	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex}
176	  \uses{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
177	
178	  In the setting of Lemma~REF, define the short complex of sheaves of \(k\)-modules
179	  \[
180	    \mathcal F_1 \xrightarrow{\;f\;} \mathcal F_2 \oplus \mathcal F_3 \xrightarrow{\;g\;} \mathcal F_4,
181	  \]
182	  where \(f\) is the biproduct lift of the two maps induced by \(X_1 \to X_2\) and \(-X_1 \to X_3\), and \(g\) is the biproduct desc of the two maps induced by \(X_2 \to X_4\) and \(X_3 \to X_4\). The composition \(g \circ f = 0\) follows from the cokernel-cofork condition of the pushout.
183	\end{definition}
184	
185	\begin{proof}
186	  
187	  \leanok
188	  The five object and morphism fields are filled directly from the pushout data; the zero field follows from the cokernel cofork condition.
189	\end{proof}
190	
191	\begin{definition}\leanok
192	[Free-\(k\)-module functor preserves monomorphisms]
193	  \label{def:Scheme_ModuleCat_free_preservesMonomorphisms}
194	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_preservesMonomorphisms}
195	  Let \(k\) be a field. The free-\(k\)-module functor preserves monomorphisms.
196	\end{definition}
197	
198	\begin{proof}
199	  \leanok
200	  An injective function between types induces an injective \(k\)-linear map on free modules because the map on finsupp supports is injective. Monomorphism status in the category of \(k\)-modules is equivalent to injectivity.
201	\end{proof}
202	
203	\begin{lemma}\leanok
204	[The first map is mono]
205	  \label{lem:Scheme_HModule_prime_shortComplex_f_mono}
206	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_f_mono}
207	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
208	
209	  In the short complex of Definition~REF, the first map \(f\) is a monomorphism.
210	\end{lemma}
211	
212	\begin{proof}
213	  
214	  \leanok
215	  The map \(f\) followed by the second projection is the free-\(k\)-module functor applied to the monomorphism \(X_1 \to X_3\), which is mono because the free functor preserves monomorphisms. Hence \(f\) itself is mono.
216	\end{proof}
217	
218	\begin{lemma}\leanok
219	[The second map is epi]
220	  \label{lem:Scheme_HModule_prime_shortComplex_g_epi}
221	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_g_epi}
222	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
223	
224	  In the short complex of Definition~REF, the second map \(g\) is an epimorphism.
225	\end{lemma}
226	
227	\begin{proof}
228	  
229	  \leanok
230	  By the pushout lemma, \(g\) is the cokernel of \(f\), and every cokernel is epi.
231	\end{proof}
232	
233	\begin{lemma}\leanok
234	[Exactness at the middle term]
235	  \label{lem:Scheme_HModule_prime_shortComplex_exact}
236	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_exact}
237	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
238	
239	  In the short complex of Definition~REF, exactness holds at the middle term: the image of \(f\) equals the kernel of \(g\).
240	\end{lemma}
241	
242	\begin{proof}
243	  
244	  \leanok
245	  By the pushout lemma, \(g\) is the cokernel of \(f\); a map is its own kernel's cokernel in an abelian category, so exactness holds at the middle term.
246	\end{proof}
247	
248	\begin{lemma}\leanok
249	[The short complex is short exact]
250	  \label{lem:Scheme_HModule_prime_shortComplex_shortExact}
251	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_shortExact}
252	  \uses{lem:Scheme_HModule_prime_shortComplex_f_mono, lem:Scheme_HModule_prime_shortComplex_g_epi, lem:Scheme_HModule_prime_shortComplex_exact}
253	
254	  The short complex of Definition~REF is short exact: its first map is mono, its second map is epi, and exactness holds at the middle term.
255	\end{lemma}
256	
257	\begin{proof}
258	  
259	  \leanok
260	  Combine Lemma~REF, Lemma~REF, and Lemma~REF.
261	\end{proof}
262	
263	\subsection{The connecting homomorphism and the long exact sequence}
264	
265	\begin{definition}\leanok
266	[Connecting homomorphism]
267	  \label{def:Scheme_HModule_prime_delta}
268	  \lean{AlgebraicGeometry.Scheme.HModule'_δ}
269	  \uses{lem:Scheme_HModule_prime_shortComplex_shortExact, def:Scheme_HModule_prime}
270	
271	  Let \(S\) be a Mayer--Vietoris square, \(\mathcal F\) a sheaf of \(k\)-modules, and \(n_0, n_1 \in \mathbb N\) with \(n_0 + 1 = n_1\). The connecting homomorphism
272	  \[
273	    \delta \;:\; H^{\prime n_0}(X_1, \mathcal F) \longrightarrow H^{\prime n_1}(X_4, \mathcal F)
274	  \]
275	  is obtained by precomposing the extension class of the short exact sequence of Lemma~REF with the canonical degree-zero map.
276	\end{definition}
277	
278	\begin{proof}
279	  
280	  \leanok
281	  The extension class lives in \(\Ext^1\) of the short exact sequence; precomposing with a map of degree zero and transporting through the additive structure yields the connecting homomorphism as a morphism of abelian groups.
282	\end{proof}
283	
284	\begin{definition}\leanok
285	[Mayer--Vietoris long exact sequence]
286	  \label{def:Scheme_HModule_prime_sequence}
287	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence}
288	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_delta}
289	
290	  In the setting of Definition~REF, define the five-term Mayer--Vietoris sequence
291	  \[
292	    H^{\prime n_0}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_0}(X_2, \mathcal F) \oplus H^{\prime n_0}(X_3, \mathcal F) \xrightarrow{\;\fromBiprod\;} H^{\prime n_0}(X_1, \mathcal F) \xrightarrow{\;\delta\;} H^{\prime n_1}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_1}(X_2, \mathcal F) \oplus H^{\prime n_1}(X_3, \mathcal F).
293	  \]
294	\end{definition}
295	
296	\begin{proof}
297	  
298	  \leanok
299	  The sequence is packaged as five composable arrows in the category of abelian groups.
300	\end{proof}
301	
302	\subsection{Comparison with the \(\Ext\) contravariant sequence}
303	
304	The following four lemmas bridge the biproduct structure on the abelian-group side with the \(\Ext\) biproduct additivity, preparing the comparison isomorphism.
305	
306	\begin{lemma}\leanok
307	[Elementwise formula for \(\toBiprod\)]
308	  \label{lem:Scheme_HModule_prime_toBiprod_apply}
309	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_apply}
310	  \uses{def:Scheme_HModule_prime_toBiprod}
311	
312	  For \(y \in H^{\prime n}(X_4, \mathcal F)\),
313	  \[
314	    \toBiprod(y) \;=\; \bigl(\mathrm{restriction}_{X_4 \to X_2}(y),\; \mathrm{restriction}_{X_4 \to X_3}(y)\bigr).
315	  \]
316	\end{lemma}
317	
318	\begin{proof}
319	  
320	  \leanok
321	  Follows from the definition of \(\toBiprod\) as a biproduct lift and the naturality of the biproduct isomorphism with the product.
322	\end{proof}
323	
324	\begin{lemma}\leanok
325	[Elementwise formula for \(\fromBiprod\)]
326	  \label{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply}
327	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_biprodIsoProd_inv_apply}
328	  \uses{def:Scheme_HModule_prime_fromBiprod}
329	
330	  For \(y_2 \in H^{\prime n}(X_2, \mathcal F)\) and \(y_3 \in H^{\prime n}(X_3, \mathcal F)\),
331	  \[
332	    \fromBiprod(y_2, y_3) \;=\; \mathrm{restriction}_{X_2 \to X_1}(y_2) \;-\; \mathrm{restriction}_{X_3 \to X_1}(y_3).
333	  \]
334	\end{lemma}
335	
336	\begin{proof}
337	  
338	  \leanok
339	  Follows from the definition of \(\fromBiprod\) as a biproduct desc and the concrete description of the biproduct isomorphism.
340	\end{proof}
341	
342	\begin{lemma}\leanok
343	[\(\Ext\) biproduct bridge for \(\toBiprod\)]
344	  \label{lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply}
345	  \lean{AlgebraicGeometry.Scheme.HModule'_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply}
346	  \uses{lem:Scheme_HModule_prime_toBiprod_apply}
347	
348	  Bridges the abelian-group biproduct isomorphism and the \(\Ext\) biproduct additivity for the \(\toBiprod\) morphism.
349	\end{lemma}
350	
351	\begin{proof}
352	  
353	  \leanok
354	  Injects through the additive equivalence and closes by categorical discharge.
355	\end{proof}
356	
357	\begin{lemma}\leanok
358	[\(\Ext\) biproduct bridge for \(\fromBiprod\)]
359	  \label{lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
360	  \lean{AlgebraicGeometry.Scheme.HModule'_mk₀_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
361	  \uses{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply, def:Scheme_HModule_prime_shortComplex}
362	
363	  Bridges the same machinery for the \(\fromBiprod\) morphism.
364	\end{lemma}
365	
366	\begin{proof}
367	  
368	  \leanok
369	  Obtains a pair from the biproduct surjectivity, then rewrites through the concrete formulas and closes by categorical discharge.
370	\end{proof}
371	
372	\begin{definition}\leanok
373	[Comparison isomorphism]
374	  \label{def:Scheme_HModule_prime_sequenceIso}
375	  \lean{AlgebraicGeometry.Scheme.HModule'_sequenceIso}
376	  \uses{def:Scheme_HModule_prime_sequence, lem:Scheme_HModule_prime_shortComplex_shortExact, def:Scheme_HModule_prime_delta, lem:Scheme_HModule_prime_toBiprod_apply, lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply, lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply, lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
377	
378	  The Mayer--Vietoris sequence of Definition~REF is canonically isomorphic to the \(\Ext\) contravariant sequence applied to the short exact sequence of Lemma~REF.
379	\end{definition}
380	
381	\begin{proof}
382	  
383	  \leanok
384	  The isomorphism is built componentwise: identity maps on the bare terms, and the composition of the biproduct isomorphism with the \(\Ext\) biproduct additivity (in the appropriate direction) on the biproduct terms. The five compatibility squares close via the four auxiliary lemmas above and the definition of the connecting homomorphism.
385	\end{proof}
386	
387	\subsection{Exactness}
388	
389	% NOTE: classical Mayer--Vietoris long exact sequence in sheaf
390	% cohomology; see Hartshorne, *Algebraic Geometry*, Ex.~III.4.6
391	% (TOC: `references/hartshorne-ag.md`) and Stacks Tag~\textbf{03B0}
392	% (Section 21.50 ``Mayer-Vietoris''). The abstract / \(k\)-module-valued
393	% repackaging here mirrors Mathlib's
394	% \texttt{CategoryTheory.MayerVietorisSquare} infrastructure.
395	\begin{theorem}\leanok
396	[Mayer--Vietoris exactness]
397	  \label{thm:Scheme_HModule_prime_sequence_exact}
398	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence_exact}
399	  \uses{def:Scheme_HModule_prime_sequenceIso, def:Scheme_HModule_prime_sequence}
400	
401	  The Mayer--Vietoris sequence of Definition~REF is exact.
402	\end{theorem}
403	
404	\begin{proof}
405	  
406	  \leanok
407	  Transport exactness along the comparison isomorphism of Definition~REF. The \(\Ext\) contravariant sequence is exact by the general exactness theorem for \(\Ext\) applied to a short exact sequence.
408	\end{proof}
409	
410	\begin{lemma}\leanok
411	[Connecting homomorphism annihilates \(\toBiprod\)]
412	  \label{lem:Scheme_HModule_prime_delta_toBiprod}
413	  \lean{AlgebraicGeometry.Scheme.HModule'_δ_toBiprod}
414	  \uses{thm:Scheme_HModule_prime_sequence_exact}
415	
416	  In the setting above,
417	  \[
418	    \delta \circ \toBiprod \;=\; 0.
419	  \]
420	\end{lemma}
421	
422	\begin{proof}
423	  
424	  \leanok
425	  Immediate from exactness at the third term of the sequence.
426	\end{proof}
427	
428	\begin{lemma}\leanok
429	[\(\fromBiprod\) annihilates the connecting homomorphism]
430	  \label{lem:Scheme_HModule_prime_fromBiprod_delta}
431	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_δ}
432	  \uses{thm:Scheme_HModule_prime_sequence_exact}
433	
434	  In the setting above,
435	  \[
436	    \fromBiprod \circ \delta \;=\; 0.
437	  \]
438	\end{lemma}
439	
440	\begin{proof}
441	  
442	  \leanok
443	  Immediate from exactness at the second term of the sequence.
444	\end{proof}
445	
446	\begin{remark}[Build-out completion]
447	  Theorem~REF closes the abstract Mayer--Vietoris long exact sequence for sheaves of \(k\)-modules. The sequence mirrors the abelian-group-valued analogue line by line, with the free-\(k\)-module functor in place of the free-abelian-group functor. The full infrastructure is now ready to be specialised to geometric covers.
448	\end{remark}
449	
450	\section{Two-affine open covers}
451	\label{sec:scheme_affineCoverMVSquare}
452	
453	A quasi-compact separated scheme \(X\) over \(k\) admits an open cover by two affines \(U_1, U_2\) whose intersection \(U_1 \cap U_2\) is again affine. Such a cover is the geometric input for the abstract Mayer--Vietoris machine. This section packages the data into a bundled structure and specialises the LES.
454	
455	\begin{definition}\leanok
456	[Two-affine Mayer--Vietoris square]
457	  \label{def:Scheme_AffineCoverMVSquare}
458	  \lean{AlgebraicGeometry.Scheme.AffineCoverMVSquare}
459	  
